// ─── Polices embarquées du thème Élégant ────────────────────────────────────────
//
// Playfair Display (serif, OFL) pour les titres/nombres, Great Vibes (script, OFL)
// pour la formule de politesse. Sous-ensemblées au jeu de caractères FR (latin +
// accents + € + ponctuation) pour limiter le poids. Sources : src/docs/fonts/.
//
// Enregistrées dans le VFS de pdfmake via registerElegantFonts() (idempotent).

type PdfMakeFontRegistrar = {
  addVirtualFileSystem: (vfs: Record<string, string>) => void;
  addFonts: (fonts: Record<string, Record<string, string>>) => void;
};

const PLAYFAIR_REGULAR_TTF_BASE64 =
  "";

const PLAYFAIR_BOLD_TTF_BASE64 =
  "";

const GREAT_VIBES_TTF_BASE64 =
  "";

/** Familles pdfmake exposées par le thème Élégant. */
export const ELEGANT_FONT_SERIF = "PlayfairDisplay";
export const ELEGANT_FONT_SCRIPT = "GreatVibes";

let registered = false;

/**
 * Ajoute Playfair Display + Great Vibes au VFS de pdfmake et déclare les familles.
 * Roboto (police par défaut de pdfmake) reste disponible. Idempotent.
 */
export function registerElegantFonts(pdfMake: PdfMakeFontRegistrar): void {
  if (registered) return;
  registered = true;

  pdfMake.addVirtualFileSystem({
    "PlayfairDisplay-Regular.ttf": PLAYFAIR_REGULAR_TTF_BASE64,
    "PlayfairDisplay-Bold.ttf": PLAYFAIR_BOLD_TTF_BASE64,
    "GreatVibes-Regular.ttf": GREAT_VIBES_TTF_BASE64,
  });

  pdfMake.addFonts({
    PlayfairDisplay: {
      normal: "PlayfairDisplay-Regular.ttf",
      bold: "PlayfairDisplay-Bold.ttf",
      italics: "PlayfairDisplay-Regular.ttf",
      bolditalics: "PlayfairDisplay-Bold.ttf",
    },
    GreatVibes: {
      normal: "GreatVibes-Regular.ttf",
      bold: "GreatVibes-Regular.ttf",
      italics: "GreatVibes-Regular.ttf",
      bolditalics: "GreatVibes-Regular.ttf",
    },
  });
}
